#define fp float

__global__ void srad_kernel(fp lambda,
                            int Nr,
                            int Nc,
                            long Ne,
                            const int* d_iN,
                            const int* d_iS,
                            const int* d_jE,
                            const int* d_jW,
                            fp* d_dN,
                            fp* d_dS,
                            fp* d_dW,
                            fp* d_dE,
                            fp q0sqr,
                            fp* d_c,
                            fp* d_I)
{
    int ei = get_global_id(0);

    if (ei < Ne) {
        int i = ei / Nc;
        int j = ei % Nc;

        fp Jc = d_I[ei];

        d_dN[ei] = d_I[d_iN[i] * Nc + j] - Jc;
        d_dS[ei] = d_I[d_iS[i] * Nc + j] - Jc;
        d_dW[ei] = d_I[i * Nc + d_jW[j]] - Jc;
        d_dE[ei] = d_I[i * Nc + d_jE[j]] - Jc;

        fp G2 = (d_dN[ei]*d_dN[ei] + d_dS[ei]*d_dS[ei] 
                + d_dW[ei]*d_dW[ei] + d_dE[ei]*d_dE[ei]) / (Jc*Jc);

        fp L = (d_dN[ei] + d_dS[ei] + d_dW[ei] + d_dE[ei]) / Jc;

        fp num = (0.5*G2) - ((1.0/16.0)*(L*L));
        fp den = 1 + (0.25*L);
        fp qsqr = num/(den*den);

        den = (qsqr-q0sqr) / (q0sqr * (1+q0sqr));
        d_c[ei] = 1.0 / (1.0+den);

        if (d_c[ei] < 0) { d_c[ei] = 0; }
        else if (d_c[ei] > 1) { d_c[ei] = 1; }
    }
}

__global__ void srad2_kernel(fp lambda,
                             int Nr,
                             int Nc,
                             long Ne,
                             const int* d_iN,
                             const int* d_iS,
                             const int* d_jE,
                             const int* d_jW,
                             fp* d_dN,
                             fp* d_dS,
                             fp* d_dW,
                             fp* d_dE,
                             fp* d_c,
                             fp* d_I)
{
    int ei = get_global_id(0);

    if (ei < Ne) {
        int i = ei / Nc;
        int j = ei % Nc;

        fp cN = d_c[ei];
        fp cS = d_c[d_iS[i] * Nc + j];
        fp cW = d_c[ei];
        fp cE = d_c[i * Nc + d_jE[j]];

        fp D = cN * d_dN[ei] + cS * d_dS[ei] + cW * d_dW[ei] + cE * d_dE[ei];

        d_I[ei] = d_I[ei] + 0.25*lambda*D;
    }
}
